```typescript
import axios from 'axios';
import { Patient, Appointment, MedicalStaff, Bill, User, LabTestCatalog, NurseServiceCatalog, Bed, OperationCatalog } from '../types';

// NETWORK CONFIGURATION
// 1. Localhost: Use relative path '/api' (uses Vite Proxy to avoid CORS locally)
// 2. Cloud IDE / Production: Use direct URL to Railway (Bypasses flaky internal proxies)
const isLocal = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';
const RAILWAY_URL = 'https://railway-hms-production.up.railway.app/api';

const API_URL = isLocal ? '/api' : RAILWAY_URL;

console.log(`🔗 Network Mode: ${isLocal ? 'Local Proxy' : 'Direct Cloud Connection'}`);
console.log(`🔗 Connecting to: ${API_URL}`);

const client = axios.create({
  baseURL: API_URL,
  headers: { 'Content-Type': 'application/json' },
});

