/**
 * Checks if a user has a specific permission.
 */
export const hasPermission = (user: User | null, permission: Permission): boolean => {
  if (!user || !user.role) return false;

  // Admin has all permissions
  if (user.role === 'admin') return true; 

  // Manager has all permissions except MANAGE_CONFIGURATION
  if (user.role === 'manager' && permission !== 'MANAGE_CONFIGURATION') return true;

  const userPermissions = ROLE_PERMISSIONS[user.role] || [];
  return userPermissions.includes(permission);
};

/**
 * Checks if a user has access to a specific route/module.
 * Used primarily for Sidebar logic.
 */
export const canAccessRoute = (user: User | null, path: string): boolean => {
  if (!user || !user.role) return false;

  // Admin has access to all routes
  if (user.role === 'admin') return true;

  // Manager has access to all routes except /configuration
  if (user.role === 'manager' && path !== '/configuration') return true;

  switch (path) {
    case '/': return true; // Everyone sees dashboard
    case '/patients': return hasPermission(user, 'VIEW_PATIENTS');
    case '/appointments': return hasPermission(user, 'VIEW_APPOINTMENTS');
    case '/billing': return hasPermission(user, 'VIEW_BILLING');
    case '/hr': return hasPermission(user, 'VIEW_HR'); // Changed from /staff to /hr
    case '/admissions': return hasPermission(user, 'VIEW_ADMISSIONS');
    case '/laboratory': return hasPermission(user, 'VIEW_LABORATORY');
    case '/operations': return hasPermission(user, 'VIEW_OPERATIONS');
    case '/reports': return hasPermission(user, 'VIEW_REPORTS');
    case '/settings': return hasPermission(user, 'VIEW_SETTINGS');
    case '/configuration': return hasPermission(user, 'MANAGE_CONFIGURATION'); // Admin only
    default: return false; // Deny access to unknown paths by default
  }
};
