```javascript
const jwt = require('jsonwebtoken');
const SECRET = process.env.JWT_SECRET || 'dev_secret_key_123'; // IMPORTANT: Set JWT_SECRET in production ENV

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// RBAC Permissions - Backend Enforcement
// This middleware now requires explicit permissions or acts as a basic role checker.
const authorizeRoles = (...requiredPermissions) => {
  return (req, res, next) => {
    if (!req.user || !req.user.role) {
      return res.status(403).json({ error: 'Access denied: User role not found.' });
    }

    const userRole = req.user.role;

    // Admin has all permissions
    if (userRole === 'admin') {
      return next();
    }

    // Manager has almost all permissions, but not 'MANAGE_CONFIGURATION'
    if (userRole === 'manager') {
      const isConfigManagement = requiredPermissions.includes('MANAGE_CONFIGURATION');
      if (!isConfigManagement) {
        return next();
      } else {
        return res.status(403).json({ error: 'Access denied: Manager cannot manage configuration.' });
      }
    }

    // For other roles, check if *any* of the user's assigned permissions match *any* of the required permissions
    // This assumes the `ROLE_PERMISSIONS` map (from frontend) is mirrored implicitly or explicitly on the backend.
    // For a simple backend, we check if the user's role is directly in the `allowedRoles` array passed for the route.
    // For granular permissions, `requiredPermissions` would be actual `Permission` types from RBAC.ts.
    // For now, let's assume `requiredPermissions` passed to `authorizeRoles` are directly valid roles for the route.
    // To make it truly granular, this backend `authorizeRoles` needs access to the `ROLE_PERMISSIONS` map.
    // For simplicity and matching current structure, we'll check if the user's role is one of the `allowedRoles` provided to the middleware.

    const allowedRolesForRoute = requiredPermissions; // In this context, `requiredPermissions` acts as `allowedRoles`

    if (!allowedRolesForRoute.includes(userRole)) {
      return res.status(403).json({ error: `Access denied. Requires one of: ${allowedRolesForRoute.join(', ')}` });
    }

    next();
  };
};

module.exports = { authenticateToken, authorizeRoles, SECRET };
