const jwt = require('jsonwebtoken');
const SECRET = process.env.JWT_SECRET || 'dev_secret_key_123'; // IMPORTANT: Set JWT_SECRET in production ENV

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

// RBAC Permissions - Backend Enforcement (Reverted to check against allowed roles for a route)
const authorizeRoles = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user || !req.user.role) {
      return res.status(403).json({ error: 'Access denied: User role not found.' });
    }

    const userRole = req.user.role;

    // Admin and Manager always have full access to these original 5 modules
    if (userRole === 'admin' || userRole === 'manager') {
      return next();
    }

    if (!allowedRoles.includes(userRole)) {
      return res.status(403).json({ error: `Access denied. Requires one of: ${allowedRoles.join(', ')}` });
    }

    next();
  };
};

module.exports = { authenticateToken, authorizeRoles, SECRET };
```

