    // src/utils/rbac.ts
    // ...

    export const hasPermission = (user: User | null, permission: Permission): boolean => {
      if (!user || !user.role) return false;

      // Admin has all permissions
      if (user.role === 'admin') return true;

      // Manager has all permissions except MANAGE_CONFIGURATION and DELETE actions
      if (user.role === 'manager') {
        if (permission === Permissions.MANAGE_CONFIGURATION || permission.startsWith('DELETE_')) { // Use Permissions.MANAGE_CONFIGURATION
          return false;
        }
        return true; // Manager has all other permissions
      }

      const userPermissions = ROLE_PERMISSIONS[user.role] || [];
      return userPermissions.includes(permission);
    };
    ```

