  const getDocFee = () => {
    const d = staff.find(s => s.id === parseInt(actionFormData.staffId));
    return d ? d.consultationFee : 0;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
