Wrap `getAll` method in `try...catch` to prevent unhandled errors from crashing the backend and ensure consistent API responses.

```javascript
const { db } = require('../config/database');

exports.getAll = (req, res) => {
  try {
    const staff = db.prepare(`
      SELECT id, employee_id as employeeId, full_name as fullName, type, department, specialization, 
      consultation_fee as consultationFee, is_available as isAvailable, email, phone 
      FROM medical_staff ORDER BY full_name
    `).all();
    // Convert 1/0 to boolean
    res.json(staff.map(s => ({ ...s, isAvailable: !!s.isAvailable })));
  } catch (err) {
    console.error('Error fetching medical staff:', err);
    res.status(500).json({ error: 'Failed to fetch medical staff.', details: err.message });
  }
};

exports.create = (req, res) => {
  const { fullName, type, department, specialization, consultationFee, email, phone } = req.body;
  // Dynamically generate employee ID based on type
  let prefix = 'STF';
  if (type === 'doctor') prefix = 'DOC';
  else if (type === 'nurse') prefix = 'NUR';
  else if (type === 'technician') prefix = 'TEC';
  else if (type === 'anesthesiologist') prefix = 'ANS';
  else if (type === 'pharmacist') prefix = 'PHR';
  else if (type === 'admin_staff') prefix = 'ADM';
  else if (type === 'hr_manager') prefix = 'HRM';

  const employeeId = `${prefix}-${Math.floor(Math.random() * 100000).toString().padStart(4, '0')}`;

  try {
    const info = db.prepare(`
      INSERT INTO medical_staff (employee_id, full_name, type, department, specialization, consultation_fee, email, phone)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(employeeId, fullName, type, department, specialization, consultationFee, email, phone);
    res.status(201).json({ id: info.lastInsertRowid, employeeId, ...req.body });
  } catch (err) {
    console.error('Error creating medical staff:', err);
    res.status(400).json({ error: err.message });
  }
};

exports.update = (req, res) => {
  const { id } = req.params;
  const updates = Object.keys(req.body);
  const allowed = ['isAvailable', 'fullName', 'phone', 'email', 'consultationFee', 'type', 'department', 'specialization'];

  const isValid = updates.every(u => allowed.includes(u));
  if (!isValid) return res.status(400).json({ error: 'Invalid updates' });

  const setClauses = [];
  const values = [];

  for (const key of updates) {
    let dbField = key;
    if (key === 'isAvailable') {
      dbField = 'is_available';
      values.push(req.body[key] ? 1 : 0);
    } else if (key === 'consultationFee') {
      dbField = 'consultation_fee';
      values.push(req.body[key]);
    } else if (key === 'fullName') {
      dbField = 'full_name';
      values.push(req.body[key]);
    } else {
      values.push(req.body[key]);
    }
    setClauses.push(`${dbField} = ?`);
  }

  try {
    const result = db.prepare(`UPDATE medical_staff SET ${setClauses.join(', ')} WHERE id = ?`).run(...values, id);
    if (result.changes === 0) return res.status(404).json({ error: 'Staff member not found' });
    res.sendStatus(200);
  } catch (err) {
    console.error('Error updating medical staff:', err);
    res.status(400).json({ error: err.message });
  }
};
