```javascript
const { db } = require('../config/database');

// Helper to safely parse JSON strings, returning undefined on error or null/empty input
function safeJSONParse(str) {
    if (typeof str !== 'string' || str === null || str.trim() === '') {
        return undefined;
    }
    try {
        const parsed = JSON.parse(str);
        // If an empty object is parsed from an empty string, treat as undefined
        if (typeof parsed === 'object' && Object.keys(parsed).length === 0 && str.trim() === '{}') {
            return undefined;
        }
        return parsed;
    } catch (e) {
        console.warn('Failed to parse JSON for patient record:', str, e);
        return undefined;
    }
}

exports.getAll = (req, res) => {
  try { // Added try-catch for getAll as well for robustness
    const patients = db.prepare('SELECT id, patient_id as patientId, full_name as fullName, phone, address, age, gender, type, has_insurance as hasInsurance, created_at as createdAt FROM patients ORDER BY created_at DESC').all();
    res.json(patients.map(p => ({ ...p, hasInsurance: !!p.hasInsurance })));
  } catch (err) {
    console.error('Error fetching all patients:', err);
