Updated page title to "HR Management (Medical Staff)" and adjusted permission checks to use `MANAGE_HR`. Staff type options in the form are now aligned with expanded staff types. Added `Array.isArray` guard to staff filtering, and fixed the typo in `consultationFee`'s `onChange` handler.

```typescript
import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Select, Modal, Badge } from '../components/UI';
import { Plus, Search, Filter, Mail, Phone, Briefcase, Lock } from 'lucide-react';
import { api } from '../services/api';
import { MedicalStaff, User } from '../types';
import { hasPermission, Permissions } from '../utils/rbac'; 

export const Staff = () => { 
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  // Form State
  const [formData, setFormData] = useState<Partial<MedicalStaff>>({
    fullName: '',
    type: 'doctor', // Default type
    department: '',
    specialization: '',
    consultationFee: 0,
    email: '',
    phone: '',
    isAvailable: true
  });

  const loadData = async () => {
    setLoading(true);
    try {
      const [data, user] = await Promise.all([
        api.getStaff().catch(err => { console.error("API Error - getStaff (HR):", err); return []; }), 
        api.me().catch(err => { console.error("API Error - me (HR):", err); return null; })
      ]);
      setStaff(Array.isArray(data) ? data : []);
      setCurrentUser(user);
    } catch (e) {
      console.error("Failed to load staff/HR data (Promise.all catch):", e);
      setStaff([]); 
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.fullName && formData.type) {
      try {
        await api.addStaff(formData as any); 
        setIsModalOpen(false);
        loadData();
        setFormData({ 
          fullName: '', type: 'doctor', department: '', 
          specialization: '', consultationFee: 0, email: '', phone: '', isAvailable: true 
        });
      } catch (err: any) {
        console.error("Failed to add staff:", err);
        alert(err.response?.data?.error || "Failed to add staff member.");
      }
    }
  };

  const toggleAvailability = async (id: number, currentStatus: boolean) => {
    if (!canManageHR) return; 
    try {
      await api.updateStaff(id, { isAvailable: !currentStatus }); 
      loadData();
    } catch (err: any) {
      console.error("Failed to update staff availability:", err);
      alert(err.response?.data?.error || "Failed to update availability.");
    }
  };

  const filteredStaff = (Array.isArray(staff) ? staff : []).filter(s => { // Guard with Array.isArray(staff)
    const matchesSearch = s.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          (s.employeeId && s.employeeId.toLowerCase().includes(searchTerm.toLowerCase()));
    const matchesFilter = filterType === 'all' || s.type === filterType;
    return matchesSearch && matchesFilter;
  });

  const canManageHR = hasPermission(currentUser, Permissions.MANAGE_HR); 

  return (
    <div className="space-y-6">
