                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-3 align-top">
                      <div className="text-sm text-gray-900 capitalize font-medium">{person.type}</div>
                      <div className="text-xs text-gray-500 flex items-center gap-1 mt-1 break-words">
