exports.update = (req, res) => {
  const { id } = req.params;
  const updates = Object.keys(req.body);
  const allowed = [
    'isAvailable', 'fullName', 'phone', 'email', 'consultationFee', 
    'type', 'department', 'specialization' 
  ];

  const isValid = updates.every(u => allowed.includes(u));
  if (!isValid) {
    return res.status(400).json({ error: 'Invalid updates provided' }); 
  }

  const setClauses = [];
  const values = [];

  for (const key of updates) {
    let dbField = key;
    // Map camelCase to snake_case for DB columns
    if (key === 'isAvailable') {
      dbField = 'is_available';
      values.push(req.body[key] ? 1 : 0);
    } else if (key === 'consultationFee') {
      dbField = 'consultation_fee';
      values.push(req.body[key]);
    } else if (key === 'fullName') {
      dbField = 'full_name';
      values.push(req.body[key]);
    } else {
      values.push(req.body[key]);
    }
    setClauses.push(`${dbField} = ?`);
  }

  try {
    const result = db.prepare(`UPDATE medical_staff SET ${setClauses.join(', ')} WHERE id = ?`).run(...values, id);
    if (result.changes === 0) return res.status(404).json({ error: 'Staff member not found' });
    res.sendStatus(200);
  } catch (err) {
    console.error(`Error updating medical staff ID ${id}:`, err); // Added specific logging
    res.status(400).json({ error: err.message });
  }
