// Helper to safely parse JSON strings, returning undefined on error or null/empty input
function safeJSONParse(str) {
    if (typeof str !== 'string' || str === null || str.trim() === '') {
        return undefined;
    }
    try {
        const parsed = JSON.parse(str);
        // If an empty object is parsed from an empty string, treat as undefined
        if (typeof parsed === 'object' && Object.keys(parsed).length === 0 && str.trim() === '{}') {
            return undefined;
        }
        return parsed;
    } catch (e) {
        console.warn('Failed to parse JSON for patient record:', str, e);
        return undefined;
    }
}

