const jwt = require('jsonwebtoken');
const { SECRET } = require('../middleware/auth');

exports.login = (req, res) => {
  const { username, password } = req.body;

  try {
    const user = db.prepare('SELECT * FROM users WHERE username = ?').get(username);

    // Fix: Explicitly check if user exists AND if user.password is available before comparing
    if (!user || !user.password || !bcrypt.compareSync(password, user.password)) {
      console.warn(`Login attempt failed for username: ${username}. Invalid credentials or missing password hash.`);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign(
      { id: user.id, username: user.username, role: user.role },
      SECRET,
      { expiresIn: '24h' }
    );

    res.json({
      token,
      user: {
        id: user.id,
        username: user.username,
        fullName: user.full_name,
        role: user.role
      }
    });
  } catch (err) {
    console.error(`Error during login for username ${username}:`, err);
    res.status(500).json({ error: 'An unexpected error occurred during login.', details: err.message });
  }
};

