  try { // Added try-catch
    const bills = db.prepare(`
      SELECT 
        b.id, b.bill_number as billNumber, b.total_amount as totalAmount, 
        b.paid_amount as paidAmount, b.status, b.bill_date as date,
        p.full_name as patientName, p.id as patientId
      FROM billing b
