  }

  if (db.prepare('SELECT COUNT(*) FROM beds').get()['COUNT(*)'] === 0) {
    const insertBed = db.prepare('INSERT INTO beds (room_number, type, status, cost_per_day) VALUES (?, ?, ?, ?)');
