exports.create = (req, res) => {
  const { patientId, staffId, datetime, type, reason, status } = req.body;

  try { // Added try-catch
    // Conflict Check
    const conflict = db.prepare(`
      SELECT id FROM appointments 
      WHERE medical_staff_id = ? AND appointment_datetime = ? AND status NOT IN ('cancelled', 'completed')
    `).get(staffId, datetime);

    if (conflict) {
