const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const { db } = require('../config/database');

const secretKey = process.env.JWT_SECRET || 's3cr3t_k3y_123';

const generateToken = (user) => {
    const payload = {
        userId: user.id,
        username: user.username,
        role: user.role,
    };
    return jwt.sign(payload, secretKey, { expiresIn: '1h' });
};

exports.login = (req, res) => {
    const { username, password } = req.body;

    if (!db) {
        console.error('DATABASE NOT AVAILABLE IN AUTH CONTROLLER! Check database.js for connection errors.');
        return res.status(500).json({ error: 'Internal Server Error' });
    }

    const prepareStatement = db.prepare('SELECT * FROM users WHERE username = ?'); // Prepare the statement

    if (!prepareStatement) {
        console.error('ERROR: Could not prepare database statement.');
        return res.status(500).json({ error: 'Internal Server Error' });
    }

    const user = prepareStatement.get(username); // Execute the prepared statement

    if (!user) {
        return res.status(401).json({ error: 'Invalid credentials' });
    }

    const passwordMatch = bcrypt.compareSync(password, user.password);

    if (passwordMatch) {
        const token = generateToken(user);
        res.json({ token, user: { id: user.id, username: user.username, role: user.role, fullName: user.full_name, email: user.email } });
    } else {
        res.status(401).json({ error: 'Invalid credentials' });
    }
};

exports.me = (req, res) => {
    if (!db) {
        console.error('DATABASE NOT AVAILABLE IN AUTH CONTROLLER! Check database.js for connection errors.');
        return res.status(500).json({ error: 'Internal Server Error' });
    }

    const userId = req.user.userId;

    const prepareStatement = db.prepare('SELECT id, username, full_name, role, email FROM users WHERE id = ?'); // Prepare the statement

    if (!prepareStatement) {
        console.error('ERROR: Could not prepare database statement.');
        return res.status(500).json({ error: 'Internal Server Error' });
    }

    const user = prepareStatement.get(userId); // Execute the prepared statement

    if (!user) {
        return res.status(404).json({ error: 'User not found' });
    }

    res.json(user);
};
