          if (!selectedStaff) {
            alert('Selected staff member not found.');
            return;
          }
          await api.createAppointment({
            patientId: selectedPatient.id,
            patientName: selectedPatient.fullName,
            staffId: selectedStaff.id,
            staffName: selectedStaff.fullName,
            datetime: `${actionFormData.date}T${actionFormData.time}`,
            type: actionFormData.subtype || 'Consultation',
            reason: actionFormData.notes || undefined,
          });
          break;
        case 'lab':
          if (selectedTests.length === 0) {
            alert('Please select at least one lab test.');
            return;
          }
          const totalLabCost = selectedTests.reduce((sum, test) => sum + test.cost, 0);
          await api.createLabRequest({
            patientId: selectedPatient.id,
            patientName: selectedPatient.fullName,
            testIds: selectedTests.map(test => test.id),
            totalCost: totalLabCost
          });
          break;
        case 'nurse':
          if (!selectedService) {
            alert('Please select a nurse service.');
            return;
          }
          await api.createNurseRequest({
            patientId: selectedPatient.id,
            patientName: selectedPatient.fullName,
            serviceName: selectedService.name,
            cost: selectedService.cost,
            notes: actionFormData.notes || undefined,
          });
          break;
        case 'admission':
          if (!selectedBed || !actionFormData.staffId || !actionFormData.date) {
            alert('Please select a bed, doctor, and entry date.');
            return;
          }
          const selectedAdmissionDoctor = staff.find(s => s.id === parseInt(actionFormData.staffId));
          if (!selectedAdmissionDoctor) {
            alert('Selected doctor not found for admission.');
            return;
          }
          await api.createAdmission({
            patientId: selectedPatient.id,
            bedId: selectedBed.id,
            doctorId: selectedAdmissionDoctor.id,
            entryDate: actionFormData.date,
            dischargeDate: actionFormData.dischargeDate || undefined,
            deposit: selectedBed.costPerDay, // Use bed cost as deposit for now
          });
          break;
        case 'operation':
          const selectedOperation = operations.find(op => op.name === actionFormData.subtype);
          if (!selectedOperation || !actionFormData.staffId || !actionFormData.date) {
            alert('Please select an operation, lead surgeon, and date.');
            return;
          }
          const leadSurgeon = staff.find(s => s.id === parseInt(actionFormData.staffId));
          if (!leadSurgeon) {
            alert('Lead surgeon not found.');
            return;
          }
          await api.createOperation({
            patientId: selectedPatient.id,
            patientName: selectedPatient.fullName,
            operationName: selectedOperation.name,
            doctorId: leadSurgeon.id,
            notes: actionFormData.notes || undefined,
            optionalFields: opDetails,
          });
          break;
        default:
          alert('Unknown action type.');
          return;
      }

      setIsActionModalOpen(false);
      setIsActionMenuOpen(false);
      alert('Request submitted successfully!');
      loadData(); // Refresh main data and potentially affected catalog states
      loadCatalogs(); // Refresh catalogs (e.g., bed availability)
      // Reset action-specific states
      setActionFormData({ staffId: '', date: new Date().toISOString().split('T')[0], time: '09:00', notes: '', subtype: '', dischargeDate: '' });
      setSelectedTests([]);
      setSelectedService(null);
      setSelectedBed(null);
      setOpDetails({ assistant: '', anesthesiologist: '', nurse: '', drugs: '', equipment: '', theater: '' });

    } catch (err: any) {
      console.error(`Failed to create ${currentAction} request:`, err);
      alert(err.response?.data?.error || `Failed to create ${currentAction} request.`);
    }
  };

  const openViewModal = async (patient: Patient) => {
    try {
      const fullDetails = await api.getPatient(patient.id);
      setSelectedPatient(fullDetails);
      setViewTab('info');
      setIsViewModalOpen(true);
    } catch (e) { 
      console.error("Failed to load patient view details:", e);
      alert("Failed to load patient details.");
    }
  };

  const filteredPatients = (Array.isArray(patients) ? patients : []).filter(p => {
    const matchesSearch = p.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.patientId.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          p.phone.includes(searchTerm);
    const matchesType = filterType === 'all' || p.type === filterType;
    const matchesGender = filterGender === 'all' || p.gender === filterGender;
    return matchesSearch && matchesType && matchesGender;
  });

  const getStatusColor = (status: Patient['type']) => {
    switch (status) {
      case 'inpatient': return 'blue';
      case 'emergency': return 'red';
      case 'outpatient': return 'gray';
      default: return 'gray';
    }
  };

  const getPatientAppointments = (patientId: number) => {
    return (Array.isArray(allAppointments) ? allAppointments : []).filter(apt => apt.patientId === patientId);
  };

  const canManagePatients = hasPermission(currentUser, Permissions.MANAGE_PATIENTS);
  const canViewPatients = hasPermission(currentUser, Permissions.VIEW_PATIENTS);
  const canManageAppointments = hasPermission(currentUser, Permissions.MANAGE_APPOINTMENTS); // Used for nurse services, appointments
  const canManageLab = hasPermission(currentUser, Permissions.MANAGE_LABORATORY);
  const canManageAdmissions = hasPermission(currentUser, Permissions.MANAGE_ADMISSIONS);
  const canManageOperations = hasPermission(currentUser, Permissions.MANAGE_OPERATIONS);

  if (!canViewPatients) {
    return (
      <Card title="Access Denied">
        <div className="flex flex-col items-center justify-center p-10 text-center text-slate-500">
          <Lock size={48} className="mb-4 text-slate-300" />
          <p className="text-lg font-semibold">You do not have permission to view patient records.</p>
          <p className="text-sm mt-2">Please contact your administrator if you believe this is an error.</p>
        </div>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h1 className="text-2xl font-bold text-gray-900">Patient Management</h1>
        {canManagePatients ? (
          <Button onClick={openCreateModal} icon={Plus}>Add New Patient</Button>
        ) : (
          <Button disabled variant="secondary" icon={Lock} className="opacity-50 cursor-not-allowed">Add New Patient</Button>
        )}
      </div>

      <Card className="!p-0 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50/50 flex flex-col gap-4">
           {/* Filters UI */}
           <div className="flex gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input type="text" placeholder="Search patients by name, ID or phone..." className="pl-10 w-full rounded-lg border-gray-300 py-2 text-slate-900 bg-white" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <Button variant={showFilters ? 'primary' : 'outline'} icon={Filter} onClick={() => setShowFilters(!showFilters)}>Filter</Button>
          </div>
          {showFilters && (
             <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 p-4 bg-white rounded-lg border border-gray-200 shadow-sm">
               <Select label="Type" value={filterType} onChange={e => setFilterType(e.target.value)}><option value="all">All</option><option value="inpatient">Inpatient</option><option value="outpatient">Outpatient</option><option value="emergency">Emergency</option></Select>
               <Select label="Gender" value={filterGender} onChange={e => setFilterGender(e.target.value)}><option value="all">All</option><option value="male">Male</option><option value="female">Female</option></Select>
             </div>
          )}
        </div>
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Patient Info</th>
                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Contact</th>
                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Type / Insurance</th>
                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Medical Info</th>
                <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {loading ? (<tr><td colSpan={5} className="text-center py-8">Loading...</td></tr>) : 
               filteredPatients.map((patient) => (
                  <tr key={patient.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-4 py-3 align-top">
                      <div className="flex items-start">
                        <div className="flex-shrink-0 h-9 w-9 rounded-full bg-primary-100 flex items-center justify-center text-primary-600 font-bold mt-1 shadow-sm">
                          {patient.fullName.charAt(0)}
                        </div>
                        <div className="ml-3">
                          <div className="text-sm font-bold text-gray-900 break-words leading-tight">{patient.fullName}</div>
                          <div className="text-xs text-gray-500 whitespace-nowrap font-mono">{patient.patientId}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-3 align-top">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center text-xs text-gray-500 whitespace-nowrap">
                          <Phone size={12} className="mr-1.5 shrink-0 text-gray-400"/> {patient.phone}
                        </div>
                        <div className="flex items-center text-xs text-gray-500 break-words">
                          <MapPin size={12} className="mr-1.5 shrink-0 text-gray-400"/> {patient.address}
                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-3 align-top">
                      <Badge color={getStatusColor(patient.type)}>{patient.type}</Badge>
                      {patient.hasInsurance && <Badge color="blue" className="ml-2"><Shield size={12} className="mr-1"/> Insured</Badge>}
                    </td>
                    <td className="px-4 py-3 text-sm text-gray-500 align-top">
                      <div className="flex items-center gap-1 text-xs text-gray-600">
                        <Heart size={12} className="text-red-400 shrink-0"/> {patient.age}y {patient.gender}
                      </div>
                      {patient.bloodGroup && <div className="flex items-center gap-1 text-xs text-gray-600 mt-1">
                        <Thermometer size={12} className="text-primary-400 shrink-0"/> BG: {patient.bloodGroup}
                      </div>}
                    </td>
                    <td className="px-4 py-3 text-right text-sm font-medium align-top whitespace-nowrap">
                      <div className="flex items-center justify-end gap-3">
                        {canManagePatients && (
                          <Button 
                            variant="ghost" 
                            size="sm" 
                            icon={Edit}
                            onClick={() => openEditModal(patient)}
                          >
                            Edit
                          </Button>
                        )}
                        <Button 
                          variant="ghost" 
                          size="sm" 
                          icon={Eye}
                          onClick={() => { setSelectedPatient(patient); setIsViewModalOpen(true); }}
                        >
                          View
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => { setSelectedPatient(patient); setIsActionMenuOpen(true); }}
                          title="Patient Actions"
                        >
                          <MoreVertical size={18}/> {/* Fix: Changed to MoreVertical */}
                        </Button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </Card>

      {/* Patient Registration/Edit Modal */}
      <Modal 
        isOpen={isFormModalOpen} 
        onClose={() => setIsFormModalOpen(false)} 
        title={isEditing ? `Edit Patient: ${selectedPatient?.fullName}` : "Register New Patient"}
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <Input 
            label="Full Name" 
            placeholder="John Doe" 
            required 
            value={formData.fullName} 
            onChange={e => setFormData({...formData, fullName: e.target.value})} 
          />
          <div className="grid grid-cols-2 gap-4">
            <Input 
              label="Age" 
              type="number" 
              required 
              value={formData.age} 
              onChange={e => setFormData({...formData, age: parseInt(e.target.value || '0')})} 
            />
            <Select 
              label="Gender" 
              required 
              value={formData.gender} 
              onChange={e => setFormData({...formData, gender: e.target.value as Patient['gender']})}
            >
              <option value="male">Male</option>
              <option value="female">Female</option>
              <option value="other">Other</option>
            </Select>
          </div>
          <Input 
            label="Phone Number" 
            placeholder="+249 9X XXX XXXX" 
            required 
            value={formData.phone} 
            onChange={e => setFormData({...formData, phone: e.target.value})} 
          />
          <Input 
            label="Address" 
            placeholder="Street 123, Khartoum" 
            value={formData.address} 
            onChange={e => setFormData({...formData, address: e.target.value})} 
          />
          <Select 
            label="Patient Type" 
            required 
            value={formData.type} 
            onChange={e => setFormData({...formData, type: e.target.value as Patient['type']})}
          >
            <option value="outpatient">Outpatient</option>
            <option value="inpatient">Inpatient</option>
            <option value="emergency">Emergency</option>
          </Select>

          <h3 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Medical History</h3>
          <Textarea 
            label="Symptoms / Chief Complaint" 
            placeholder="e.g., Fever, headache, cough..." 
            rows={3}
            value={formData.symptoms} 
            onChange={e => setFormData({...formData, symptoms: e.target.value})} 
          />
          <Textarea 
            label="Past Medical History" 
            placeholder="e.g., Diabetes, Hypertension, past surgeries..." 
            rows={3}
            value={formData.medicalHistory} 
            onChange={e => setFormData({...formData, medicalHistory: e.target.value})} 
          />
          <Input 
            label="Allergies" 
            placeholder="e.g., Penicillin, Peanuts" 
            value={formData.allergies} 
            onChange={e => setFormData({...formData, allergies: e.target.value})} 
          />
          <Input 
            label="Blood Group" 
            placeholder="e.g., A+, O-" 
            value={formData.bloodGroup} 
            onChange={e => setFormData({...formData, bloodGroup: e.target.value})} 
          />

          <h3 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Emergency Contact</h3>
          <Input 
            label="Contact Name" 
            placeholder="Relative's Full Name" 
            value={formData.emergencyName} 
            onChange={e => setFormData({...formData, emergencyName: e.target.value})} 
          />
          <Input 
            label="Contact Phone" 
            placeholder="+249 9X XXX XXXX" 
            value={formData.emergencyPhone} 
            onChange={e => setFormData({...formData, emergencyPhone: e.target.value})} 
          />
          <Input 
            label="Relation" 
            placeholder="e.g., Mother, Brother" 
            value={formData.emergencyRelation} 
            onChange={e => setFormData({...formData, emergencyRelation: e.target.value})} 
          />

          <h3 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Insurance Details</h3>
          <div className="flex items-center gap-3">
            <input 
              type="checkbox" 
              id="hasInsurance" 
              className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
              checked={formData.hasInsurance}
              onChange={e => setFormData({...formData, hasInsurance: e.target.checked})}
            />
            <label htmlFor="hasInsurance" className="text-sm font-medium text-slate-700">Patient has insurance</label>
          </div>

          {formData.hasInsurance && (
            <>
              <Select 
                label="Insurance Provider" 
                value={formData.insProvider} 
                onChange={e => setFormData({...formData, insProvider: e.target.value})}
              >
                <option value="">Select Provider</option>
                {SUDAN_INSURANCE_PROVIDERS.map(p => <option key={p} value={p}>{p}</option>)}
              </Select>
              <Input 
                label="Policy Number" 
                placeholder="ABC123456" 
                value={formData.insPolicy} 
                onChange={e => setFormData({...formData, insPolicy: e.target.value})} 
              />
              <Input 
                label="Expiry Date" 
                type="date" 
                value={formData.insExpiry} 
                onChange={e => setFormData({...formData, insExpiry: e.target.value})} 
              />
              <Textarea 
                label="Insurance Notes" 
                placeholder="Additional details about the policy..." 
                rows={2}
                value={formData.insNotes} 
                onChange={e => setFormData({...formData, insNotes: e.target.value})} 
              />
            </>
          )}

          <div className="pt-4 flex justify-end gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsFormModalOpen(false)}>Cancel</Button>
            <Button type="submit">{isEditing ? "Save Changes" : "Register Patient"}</Button>
          </div>
        </form>
      </Modal>

      {/* View Patient Modal */}
      {selectedPatient && (
        <Modal 
          isOpen={isViewModalOpen} 
          onClose={() => setIsViewModalOpen(false)} 
          title={`Patient Details: ${selectedPatient.fullName}`}
        >
          <div className="flex border-b border-slate-100 mb-4">
            <button 
              className={`py-2 px-4 text-sm font-medium ${viewTab === 'info' ? 'border-b-2 border-primary-600 text-primary-600' : 'text-slate-500 hover:text-slate-700'}`}
              onClick={() => setViewTab('info')}
            >
              General Info
            </button>
            <button 
              className={`py-2 px-4 text-sm font-medium ${viewTab === 'records' ? 'border-b-2 border-primary-600 text-primary-600' : 'text-slate-500 hover:text-slate-700'}`}
              onClick={() => setViewTab('records')}
            >
              Medical Records & History
            </button>
          </div>

          {viewTab === 'info' && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <InfoItem label="Patient ID">{selectedPatient.patientId}</InfoItem>
                <InfoItem label="Full Name">{selectedPatient.fullName}</InfoItem>
                <InfoItem label="Age">{selectedPatient.age}</InfoItem>
                <InfoItem label="Gender">{selectedPatient.gender}</InfoItem>
                <InfoItem label="Phone">{selectedPatient.phone}</InfoItem>
                <InfoItem label="Address">{selectedPatient.address}</InfoItem>
                <InfoItem label="Type"><Badge color={getStatusColor(selectedPatient.type)}>{selectedPatient.type}</Badge></InfoItem>
                <InfoItem label="Registered On">{new Date(selectedPatient.createdAt).toLocaleDateString()}</InfoItem>
              </div>

              <h4 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Emergency Contact</h4>
              {selectedPatient.emergencyContact ? (
                <div className="grid grid-cols-2 gap-4">
                  <InfoItem label="Name">{selectedPatient.emergencyContact.name}</InfoItem>
                  <InfoItem label="Phone">{selectedPatient.emergencyContact.phone}</InfoItem>
                  <InfoItem label="Relation">{selectedPatient.emergencyContact.relation}</InfoItem>
                </div>
              ) : <p className="text-slate-500">No emergency contact details.</p>}

              <h4 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Insurance Details</h4>
              {selectedPatient.hasInsurance && selectedPatient.insuranceDetails ? (
                <div className="grid grid-cols-2 gap-4">
                  <InfoItem label="Provider">{selectedPatient.insuranceDetails.provider}</InfoItem>
                  <InfoItem label="Policy Number">{selectedPatient.insuranceDetails.policyNumber}</InfoItem>
                  <InfoItem label="Expiry Date">{selectedPatient.insuranceDetails.expiryDate}</InfoItem>
                  {selectedPatient.insuranceDetails.notes && <InfoItem label="Notes">{selectedPatient.insuranceDetails.notes}</InfoItem>}
                </div>
              ) : <p className="text-slate-500">Patient does not have insurance details.</p>}
            </div>
          )}

          {viewTab === 'records' && (
            <div className="space-y-4">
              <h4 className="font-bold text-slate-700">Key Medical Information</h4>
              <div className="grid grid-cols-2 gap-4">
                <InfoItem label="Blood Group">{selectedPatient.bloodGroup || 'N/A'}</InfoItem>
                <InfoItem label="Allergies">{selectedPatient.allergies || 'None'}</InfoItem>
              </div>

              <h4 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Symptoms</h4>
              <p className="text-slate-700 text-sm bg-slate-50 p-3 rounded-lg border border-slate-100">{selectedPatient.symptoms || 'No symptoms recorded.'}</p>

              <h4 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Medical History</h4>
              <p className="text-slate-700 text-sm bg-slate-50 p-3 rounded-lg border border-slate-100">{selectedPatient.medicalHistory || 'No medical history recorded.'}</p>

              <h4 className="font-bold text-slate-700 mt-6 pt-4 border-t border-slate-100">Appointments ({getPatientAppointments(selectedPatient.id).length})</h4>
              {getPatientAppointments(selectedPatient.id).length > 0 ? (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-slate-100">
                    <thead className="bg-slate-50">
                      <tr>
                        <th className="px-3 py-2 text-left text-xs font-semibold text-slate-500 uppercase">Doctor</th>
                        <th className="px-3 py-2 text-left text-xs font-semibold text-slate-500 uppercase">Date & Time</th>
                        <th className="px-3 py-2 text-left text-xs font-semibold text-slate-500 uppercase">Type</th>
                        <th className="px-3 py-2 text-left text-xs font-semibold text-slate-500 uppercase">Status</th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-slate-100">
                      {getPatientAppointments(selectedPatient.id).map(apt => (
                        <tr key={apt.id}>
                          <td className="px-3 py-2 text-sm text-slate-700">{apt.staffName}</td>
                          <td className="px-3 py-2 text-sm text-slate-700 whitespace-nowrap">{new Date(apt.datetime).toLocaleString()}</td>
                          <td className="px-3 py-2 text-sm text-slate-700">{apt.type}</td>
                          <td className="px-3 py-2"><Badge color={apt.status === 'confirmed' ? 'green' : apt.status === 'cancelled' ? 'red' : 'yellow'}>{apt.status}</Badge></td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              ) : <p className="text-slate-500">No appointments found for this patient.</p>}
            </div>
          )}
        </Modal>
      )}

      {/* Patient Action Menu Modal */}
      {selectedPatient && (
        <Modal 
          isOpen={isActionMenuOpen} 
          onClose={() => setIsActionMenuOpen(false)} 
          title={`Actions for ${selectedPatient.fullName}`}
        >
          <p className="text-slate-600 mb-4">Select an action to perform for this patient:</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <ActionButton
              icon={Calendar}
              title="Schedule Appointment"
              description="Book a new consultation or follow-up."
              onClick={() => { setCurrentAction('appointment'); setIsActionModalOpen(true); }}
              disabled={!canManageAppointments}
            />
            <ActionButton
              icon={FlaskConical}
              title="Order Lab Test"
              description="Request laboratory investigations."
              onClick={() => { setCurrentAction('lab'); setIsActionModalOpen(true); }}
              disabled={!canManageLab}
            />
            <ActionButton
              icon={Stethoscope}
              title="Request Nurse Service"
              description="Order nursing care like injections or wound dressing."
              onClick={() => { setCurrentAction('nurse'); setIsActionModalOpen(true); }}
              disabled={!canManageAppointments} // Assuming receptionists/doctors can request nurse services
            />
            <ActionButton
              icon={Bed}
              title="Admit Patient"
              description="Assign a bed and admit to a ward."
              onClick={() => { setCurrentAction('admission'); setIsActionModalOpen(true); }}
              disabled={!canManageAdmissions}
            />
            <ActionButton
              icon={Activity}
              title="Schedule Operation"
              description="Plan a surgical procedure."
              onClick={() => { setCurrentAction('operation'); setIsActionModalOpen(true); }}
              disabled={!canManageOperations}
            />
          </div>
        </Modal>
      )}

      {/* Dynamic Action Modal */}
      {selectedPatient && (
        <Modal
          isOpen={isActionModalOpen}
          onClose={() => setIsActionModalOpen(false)}
          title={
            currentAction === 'appointment' ? 'Schedule New Appointment' :
            currentAction === 'lab' ? 'Order Lab Tests' :
            currentAction === 'nurse' ? 'Request Nurse Service' :
            currentAction === 'admission' ? 'Admit Patient' :
            currentAction === 'operation' ? 'Schedule Operation' :
            'Patient Action'
          }
        >
          <form onSubmit={handleActionSubmit} className="space-y-4">
            {currentAction === 'appointment' && (
              <>
                <Select
                  label="Select Doctor"
                  required
                  name="staffId"
                  value={actionFormData.staffId}
                  onChange={handleActionFormChange}
                >
                  <option value="">Select a doctor...</option>
                  {(Array.isArray(staff) ? staff : []).filter(s => s.type === 'doctor').map(s => (
