    setLoading(true);
    try {
      const [apts, pts, stf, user] = await Promise.all([
        api.getAppointments().catch(err => { console.error("API Error - getAppointments:", err); return []; }),
        api.getPatients().catch(err => { console.error("API Error - getPatients (Appointments):", err); return []; }),
        api.getStaff().catch(err => { console.error("API Error - getStaff (Appointments):", err); return []; }),
        api.me().catch(err => { console.error("API Error - me (Appointments):", err); return null; })
      ]);
      setAppointments(Array.isArray(apts) ? apts : []);
      setPatients(Array.isArray(pts) ? pts : []);
      setStaff(Array.isArray(stf) ? stf : []);
      setCurrentUser(user);
    } catch (e) {
      console.error("Failed to load core data (Promise.all catch) in Appointments:", e);
      setAppointments([]);
      setPatients([]);
      setStaff([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    const patient = (Array.isArray(patients) ? patients : []).find(p => p.id === parseInt(formData.patientId));
    const doctor = (Array.isArray(staff) ? staff : []).find(s => s.type === 'doctor' && s.id === parseInt(formData.staffId)); // Filter by doctor type

    if (patient && doctor && formData.date && formData.time) {
      try {
        await api.createAppointment({
          patientId: patient.id,
          patientName: patient.fullName,
          staffId: doctor.id,
          staffName: doctor.fullName,
          datetime: `${formData.date}T${formData.time}`,
