import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Select, Modal, Badge } from '../components/UI';
import { Plus, Calendar, Clock, User, Lock } from 'lucide-react';
import { api } from '../services/api';
import { Patient, Appointment, MedicalStaff, User as UserType } from '../types';
import { hasPermission, Permissions } from '../utils/rbac'; // Import Permissions

export const Appointments = () => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const [currentUser, setCurrentUser] = useState<UserType | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  // Form
  const [formData, setFormData] = useState({
    patientId: '',
    staffId: '',
    date: '',
    time: '',
    type: 'Consultation'
  });

  const loadData = async () => {
    setLoading(true);
    try {
      const [apts, pts, stf, user] = await Promise.all([
        api.getAppointments().catch(err => { console.error("API Error - getAppointments:", err); return []; }),
        api.getPatients().catch(err => { console.error("API Error - getPatients (Appointments):", err); return []; }),
        api.getStaff().catch(err => { console.error("API Error - getStaff (Appointments):", err); return []; }),
        api.me().catch(err => { console.error("API Error - me (Appointments):", err); return null; })
      ]);
      setAppointments(Array.isArray(apts) ? apts : []);
      setPatients(Array.isArray(pts) ? pts : []);
      setStaff(Array.isArray(stf) ? stf : []);
      setCurrentUser(user);
    } catch (e) {
      console.error("Failed to load core data (Promise.all catch) in Appointments:", e);
      setAppointments([]);
      setPatients([]);
      setStaff([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    const patient = (Array.isArray(patients) ? patients : []).find(p => p.id === parseInt(formData.patientId));
    const doctor = (Array.isArray(staff) ? staff : []).find(s => s.type === 'doctor' && s.id === parseInt(formData.staffId)); // Filter by doctor type

    if (patient && doctor && formData.date && formData.time) {
      try {
        await api.createAppointment({
          patientId: patient.id,
          patientName: patient.fullName,
          staffId: doctor.id,
          staffName: doctor.fullName,
          datetime: `${formData.date}T${formData.time}`,
          type: formData.type
        });
        setIsModalOpen(false);
        loadData();
        setFormData({ patientId: '', staffId: '', date: '', time: '', type: 'Consultation' });
      } catch (err: any) {
        console.error("Failed to create appointment:", err);
        alert(err.response?.data?.error || "Failed to create appointment.");
      }
    } else {
      alert("Please select a patient, doctor, and a valid date/time.");
    }
  };

  const canManageAppointments = hasPermission(currentUser, Permissions.MANAGE_APPOINTMENTS); // Use Permissions

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-gray-900">Appointments</h1>
        {canManageAppointments ? (
          <Button onClick={() => setIsModalOpen(true)} icon={Plus}>Book Appointment</Button>
        ) : (
          <Button 
            disabled 
            className="opacity-50 cursor-not-allowed bg-slate-100 text-slate-400 border-slate-200" 
            variant="secondary"
            icon={Lock}
          >
            Book Appointment
          </Button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-3">
          <Card className="!p-0 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Appt ID</th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Patient</th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Doctor</th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Date & Time</th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Status</th>
                    <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase whitespace-nowrap">Actions</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {/* Guard with Array.isArray(appointments) */}
                  {Array.isArray(appointments) && appointments.map((apt) => (
                    <tr key={apt.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3 text-sm font-medium text-gray-900 align-top whitespace-nowrap">
                        <span className="font-mono bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded text-xs">{apt.appointmentNumber}</span>
                      </td>
                      <td className="px-4 py-3 align-top">
                         <div className="text-sm text-gray-900 font-bold break-words leading-tight">{apt.patientName}</div>
                      </td>
                      <td className="px-4 py-3 align-top">
                        <div className="text-sm text-gray-600 break-words leading-tight">{apt.staffName}</div>
                      </td>
                      <td className="px-4 py-3 text-sm text-gray-500 align-top whitespace-nowrap">
                        <div className="flex flex-col">
                          <span className="font-medium text-gray-800">{new Date(apt.datetime).toLocaleDateString()}</span>
                          <span className="text-xs text-gray-400">{new Date(apt.datetime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                        </div>
                      </td>
                      <td className="px-4 py-3 align-top whitespace-nowrap">
                         <Badge color={apt.status === 'confirmed' ? 'green' : apt.status === 'cancelled' ? 'red' : 'yellow'}>{apt.status}</Badge>
                      </td>
                      <td className="px-4 py-3 text-right text-sm align-top whitespace-nowrap">
                        {apt.status === 'pending' && canManageAppointments && (
                          <button 
                            onClick={() => { api.updateAppointmentStatus(apt.id, 'confirmed'); loadData(); }}
                            className="text-green-600 hover:text-green-800 font-medium mr-3 transition-colors"
                          >
                            Confirm
                          </button>
                        )}
                         <button className="text-gray-400 hover:text-gray-600 transition-colors">Details</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </Card>
        </div>
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="New Appointment">
        <form onSubmit={handleCreate} className="space-y-4">
          <Select 
            label="Select Patient" 
            required
            value={formData.patientId} 
            onChange={e => setFormData({...formData, patientId: e.target.value})}
          >
            <option value="">Select a patient...</option>
            {/* Guard with Array.isArray(patients) */}
            {Array.isArray(patients) && patients.map(p => <option key={p.id} value={p.id}>{p.fullName} ({p.patientId})</option>)}
          </Select>

          <Select 
            label="Select Doctor" 
            required
            value={formData.staffId} 
            onChange={e => setFormData({...formData, staffId: e.target.value})}
          >
             <option value="">Select a doctor...</option>
             {/* Guard with Array.isArray(staff) */}
             {Array.isArray(staff) && staff.filter(s => s.type === 'doctor').map(s => <option key={s.id} value={s.id}>{s.fullName} - {s.specialization}</option>)}
          </Select>

          <div className="grid grid-cols-2 gap-4">
            <Input 
              label="Date" 
              type="date" 
              required
              value={formData.date}
              onChange={e => setFormData({...formData, date: e.target.value})}
            />
            <Input 
              label="Time" 
              type="time" 
              required
              value={formData.time}
              onChange={e => setFormData({...formData, time: e.target.value})}
            />
          </div>

          <Select 
            label="Type" 
            value={formData.type} 
            onChange={e => setFormData({...formData, type: e.target.value})}
          >
            <option value="Consultation">General Consultation</option>
            <option value="Follow-up">Follow-up</option>
            <option value="Emergency">Emergency</option>
            <option value="Lab">Lab Test</option>
          </Select>

          <div className="pt-4 flex justify-end gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>Cancel</Button>
             <Button type="submit">Schedule</Button>
          </div>
        </form>
      </Modal>
    </div>
  );
};--- START OF FILE pages/Billing.tsx ---

import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Select, Modal, Badge } from '../components/UI';
import { Plus, Printer, Download, X, Lock } from 'lucide-react';
import { api } from '../services/api';
import { Bill, Patient, Appointment } from '../types';
import { hasPermission, Permissions } from '../utils/rbac'; // Import Permissions

export const Billing = () => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]); // Not directly used in UI, but fetched
  const [currentUser, setCurrentUser] = useState<any>(null);
  // Add state for modal visibility and selected bill
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedBill, setSelectedBill] = useState<Bill | null>(null);

  // Form
  const [formData, setFormData] = useState({
    patientId: '',
    amount: '',
    description: ''
  });

  const loadData = async () => {
    try {
      const [b, p, a, u] = await Promise.all([
        api.getBills().catch(err => { console.error("API Error - getBills:", err); return []; }),
        api.getPatients().catch(err => { console.error("API Error - getPatients (Billing):", err); return []; }),
        api.getAppointments().catch(err => { console.error("API Error - getAppointments (Billing):", err); return []; }), // Still fetch, but guard usage
        api.me().catch(err => { console.error("API Error - me (Billing):", err); return null; })
      ]);
      setBills(Array.isArray(b) ? b : []);
      setPatients(Array.isArray(p) ? p : []);
      setAppointments(Array.isArray(a) ? a : []);
      setCurrentUser(u);
    } catch (error) {
      console.error("Failed to load core data (Promise.all catch) in Billing:", error);
      setBills([]);
      setPatients([]);
      setAppointments([]);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    const patient = (Array.isArray(patients) ? patients : []).find(p => p.id === parseInt(formData.patientId));
    if (patient) {
      try {
        await api.createBill({
          patientId: patient.id,
          patientName: patient.fullName,
          totalAmount: parseFloat(formData.amount),
          date: new Date().toISOString().split('T')[0],
          items: [{ description: formData.description, amount: parseFloat(formData.amount) }]
        });
        setIsModalOpen(false);
        loadData();
        setFormData({patientId: '', amount: '', description: ''}); // Clear form
      } catch (err: any) {
